  1	import React, {
  2	  Dispatch,
  3	  FC,
  4	  SetStateAction,
  5	  useCallback,
  6	  useEffect,
  7	  useRef,
  8	  useState,
  9	} from 'react';
 10	
 11	import { V1VirtualMachineInstance } from '@kubevirt-ui/kubevirt-api/kubevirt';
 12	import LoadingEmptyState from '@kubevirt-utils/components/LoadingEmptyState/LoadingEmptyState';
 13	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 14	import { kubevirtConsole } from '@kubevirt-utils/utils/utils';
 15	import { WSFactory } from '@openshift-console/dynamic-plugin-sdk/lib/utils/k8s/ws-factory';
 16	import { Button, EmptyState, EmptyStateBody, EmptyStateFooter } from '@patternfly/react-core';
 17	
 18	import { INSECURE, SECURE } from '../../utils/constants';
 19	import { isConnectionEncrypted } from '../../utils/utils';
 20	import { ConsoleState, WS, WSFactoryExtends, WSS } from '../utils/ConsoleConsts';
 21	import useCopyPasteConsole from '../utils/hooks/useCopyPasteConsole';
 22	
 23	import { WebSocket } from './utils/serialConsole';
 24	import { XTerm } from './Xterm/Xterm';
 25	
 26	const { destroyed, init, open } = ConsoleState;
 27	
 28	type SerialConsoleConnectorProps = {
 29	  onConnect?: Dispatch<SetStateAction<WebSocket>>;
 30	  vmi: V1VirtualMachineInstance;
 31	};
 32	
 33	const SerialConsoleConnector: FC<SerialConsoleConnectorProps> = ({ onConnect, vmi }) => {
 34	  const { t } = useKubevirtTranslation();
 35	  const [status, setStatus] = useState(init);
 36	  const pasteText = useCopyPasteConsole();
 37	
 38	  const terminalRef = useRef(null);
 39	  const [socket, setSocket] = useState<WebSocket>(null);
 40	
 41	  const connect = useCallback(() => {
 42	    if (socket) {
 43	      socket.destroy();
 44	      setStatus(init);
 45	    }
 46	
 47	    const websocketOptions = {
 48	      host: `${isConnectionEncrypted() ? WSS : WS}://${window.location.hostname}:${
 49	        window.location.port || (isConnectionEncrypted() ? SECURE : INSECURE)
 50	      }`,
 51	      jsonParse: false,
 52	      path: `/api/kubernetes/apis/subresources.kubevirt.io/v1/namespaces/${vmi?.metadata?.namespace}/virtualmachineinstances/${vmi?.metadata?.name}/console`,
 53	      reconnect: false,
 54	      subprotocols: ['plain.kubevirt.io'],
 55	    };
 56	
 57	    const createdSocket = new WSFactory(`${vmi?.metadata?.name}-serial`, websocketOptions)
 58	      .onmessage((data: Blob) => {
 59	        data.text().then((text) => {
 60	          terminalRef.current.onDataReceived(text);
 61	        });
 62	      })
 63	      .onopen(() => {
 64	        setStatus(open);
 65	      })
 66	      .onclose(function () {
 67	        this?.destroy();
 68	        setStatus(destroyed);
 69	      })
 70	      .ondestroy(() => setStatus(destroyed))
 71	      .onerror((event) => {
 72	        kubevirtConsole.log('WebSocket error received: ', event);
 73	      }) as WSFactoryExtends;
 74	    createdSocket.onPaste = async function () {
 75	      try {
 76	        const text = await navigator.clipboard.readText();
 77	        this?.send(new Blob([text]));
 78	      } catch {
 79	        this?.send(new Blob([pasteText?.current]));
 80	      }
 81	    };
 82	    setSocket(createdSocket);
 83	    onConnect?.(createdSocket);
 84	  }, [socket, vmi?.metadata?.namespace, vmi?.metadata?.name, onConnect, pasteText]);
 85	
 86	  useEffect(() => {
 87	    !socket && connect();
 88	  }, [connect, socket]);
 89	
 90	  return (
 91	    <>
 92	      {status === open && (
 93	        <XTerm
 94	          onData={(data) => {
 95	            socket?.send(new Blob([data]));
 96	          }}
 97	          fontFamily={'monospace'}
 98	          fontSize={12}
 99	          innerRef={terminalRef}
100	        />
101	      )}
102	      {status === destroyed && (
103	        <EmptyState>
104	          <EmptyStateBody>{t('Click Connect to open serial console.')}</EmptyStateBody>
105	          <EmptyStateFooter>
106	            <Button onClick={connect}>{t('Connect')}</Button>
107	          </EmptyStateFooter>
108	        </EmptyState>
109	      )}
110	      {status === init && <LoadingEmptyState bodyContents={t('Loading ...')} />}
111	    </>
112	  );
113	};
114	
115	export default SerialConsoleConnector;

